package commands

import (
	"errors"

	"github.com/google/uuid"
)

type Topic struct {
	topicId            string
	title              string
	description        string
	prerequisites      string
	knowledge          string
	flow               string
	quiz               string
	completionCriteria string
	number             int
}

type Section struct {
	sectionId   string
	title       string
	description string
	number      int
	topics      []Topic
}

type Author struct {
	authorId string
	name     string
}

type Category struct {
	categoryId string
	name       string
}

type Course struct {
	courseId      string
	title         string
	description   string
	slug          string
	tags          []string
	publishStatus string
	category      Category
	publishedAt   *string
	author        Author
	visibility    string
	sections      []Section
}

var ErrEnrollmentNotAllowed = errors.New("enrollment not allowed")
var ErrTopicNotFoundInCourse = errors.New("topic not found in course")

func (course *Course) checkEnrollable(userId uuid.UUID) error {
	if course.publishStatus != "published" && course.author.authorId != userId.String() {
		return ErrEnrollmentNotAllowed
	}
	return nil
}

func (course *Course) findTopicById(topicId uuid.UUID) (Topic, error) {
	for _, section := range course.sections {
		for _, topic := range section.topics {
			if topic.topicId == topicId.String() {
				return topic, nil
			}
		}
	}
	return Topic{}, ErrTopicNotFoundInCourse
}

DROP TABLE user_topic_progresses;

CREATE TABLE enrollments (
    user_id UUID NOT NULL,
    course_id UUID NOT NULL,
    enrolled_at TIMESTAMPTZ NOT NULL,

    _created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    _updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT pk_enrollments PRIMARY KEY (user_id, course_id),
    CONSTRAINT fk_enrollments_user_id FOREIGN KEY (user_id) REFERENCES users(user_id),
    CONSTRAINT fk_enrollments_course_id FOREIGN KEY (course_id) REFERENCES courses(course_id)
);

CREATE INDEX idx_enrollments_course_id ON enrollments USING BTREE (course_id);

CREATE TRIGGER trigger_enrollments_meta_updated_at BEFORE
UPDATE
    ON enrollments FOR EACH ROW EXECUTE FUNCTION update_meta_updated_at();

CREATE TABLE topic_progresses (
    user_id UUID NOT NULL,
    course_id UUID NOT NULL,
    course_section_topic_id UUID NOT NULL,
    status TEXT NOT NULL,

    _created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
    _updated_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),

    CONSTRAINT pk_topic_progresses PRIMARY KEY (user_id, course_id, course_section_topic_id),
    CONSTRAINT fk_topic_progresses_enrollment FOREIGN KEY (user_id, course_id) REFERENCES enrollments(user_id, course_id),
    CONSTRAINT fk_topic_progresses_course_section_topic_id FOREIGN KEY (course_section_topic_id) REFERENCES course_section_topics(course_section_topic_id)
);

COMMENT ON COLUMN topic_progresses.status IS 'IN_PROGRESS = 開始済み, COMPLETED = 完了済み, 開始していない場合はレコード自体がないので値として持たない';

CREATE INDEX idx_topic_progresses_course_section_topic_id ON topic_progresses USING BTREE (course_section_topic_id);

CREATE TRIGGER trigger_topic_progresses_meta_updated_at BEFORE
UPDATE
    ON topic_progresses FOR EACH ROW EXECUTE FUNCTION update_meta_updated_at();

package commands

import (
	"context"
	"encoding/json"
	"time"

	"github.com/google/uuid"
	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type SqrcCourseRepository struct {
	sqrc db.Querier
}

func NewSqrcCourseRepository(q db.Querier) *SqrcCourseRepository {
	return &SqrcCourseRepository{sqrc: q}
}

func (repository *SqrcCourseRepository) getCourseByCourseId(ctx context.Context, courseId uuid.UUID) (Course, error) {
	var courseIdUuid pgtype.UUID

	if err := courseIdUuid.Scan(courseId.String()); err != nil {
		return Course{}, err
	}

	courseRaw, err := repository.sqrc.GetCourseById(ctx, courseIdUuid)
	if err != nil {
		return Course{}, err
	}

	return toCourse(courseRaw), nil
}

func toCourse(raw db.GetCourseByIdRow) Course {
	var tags []string
	json.Unmarshal(raw.Tags, &tags)

	type topicRaw struct {
		CourseSectionTopicId string `json:"course_section_topic_id"`
		Title                string `json:"title"`
		Description          string `json:"description"`
		Prerequisites        string `json:"prerequisites"`
		Knowledge            string `json:"knowledge"`
		Flow                 string `json:"flow"`
		Quiz                 string `json:"quiz"`
		CompletionCriteria   string `json:"completion_criteria"`
	}
	type sectionRaw struct {
		CourseSectionId string     `json:"course_section_id"`
		Title           string     `json:"title"`
		Description     string     `json:"description"`
		Topics          []topicRaw `json:"topics"`
	}

	var sectionsRaw []sectionRaw
	json.Unmarshal(raw.Sections, &sectionsRaw)

	sections := make([]Section, len(sectionsRaw))
	for i, s := range sectionsRaw {
		topics := make([]Topic, len(s.Topics))
		for j, t := range s.Topics {
			topics[j] = Topic{
				topicId:            t.CourseSectionTopicId,
				title:              t.Title,
				description:        t.Description,
				prerequisites:      t.Prerequisites,
				knowledge:          t.Knowledge,
				flow:               t.Flow,
				quiz:               t.Quiz,
				completionCriteria: t.CompletionCriteria,
				number:             j,
			}
		}
		sections[i] = Section{
			sectionId:   s.CourseSectionId,
			title:       s.Title,
			description: s.Description,
			number:      i,
			topics:      topics,
		}
	}

	var publishedAt *string
	if raw.PublishedAt.Valid {
		t := raw.PublishedAt.Time.Format(time.RFC3339)
		publishedAt = &t
	}

	return Course{
		courseId:      raw.CourseID.String(),
		title:         raw.Title,
		description:   raw.Description,
		slug:          raw.Slug,
		tags:          tags,
		publishStatus: raw.PublishStatus,
		category: Category{
			categoryId: raw.CategoryID.String(),
			name:       raw.CategoryName,
		},
		publishedAt: publishedAt,
		author: Author{
			authorId: raw.AuthorID.String(),
			name:     raw.AuthorName,
		},
		visibility: raw.Visibility,
		sections:   sections,
	}
}

